def gen(rng, size):
    m = rng.randint(2, max(2, min(size, 18)))
    n = rng.randint(2, max(2, min(size, 18)))
    grid = []
    for r in range(m):
        row = []
        for c in range(n):
            x = rng.random()
            if x < 0.12:
                row.append(2)
            elif x < 0.18:
                row.append(1)
            else:
                row.append(0)
        grid.append(row)
    grid[0][0] = 0
    grid[m - 1][n - 1] = 0
    return [grid]

