from collections import deque
class Solution:
    def maximumMinutes(self, grid):
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        DIRS = ((1, 0), (-1, 0), (0, 1), (0, -1))
        def bfs(sources):
            dist = [[INF] * n for _ in range(m)]
            q = deque()
            for r, c in sources:
                dist[r][c] = 0
                q.append((r, c))
            while q:
                r, c = q.popleft()
                for dr, dc in DIRS:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 2 and dist[nr][nc] == INF:
                        dist[nr][nc] = dist[r][c] + 1
                        q.append((nr, nc))
            return dist
        fires = [(r, c) for r in range(m) for c in range(n) if grid[r][c] == 1]
        fire_time = bfs(fires)
        person_time = bfs([(0, 0)])
        if person_time[m - 1][n - 1] == INF:
            return -1
        def survives(d):
            pd = [[INF] * n for _ in range(m)]
            q = deque()
            if d < fire_time[0][0]:
                pd[0][0] = d
                q.append((0, 0))
            while q:
                r, c = q.popleft()
                for dr, dc in DIRS:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 2 and pd[nr][nc] == INF:
                        arrive = pd[r][c] + 1
                        if nr == m - 1 and nc == n - 1:
                            if arrive <= fire_time[nr][nc]:
                                return True
                            continue
                        if arrive < fire_time[nr][nc]:
                            pd[nr][nc] = arrive
                            q.append((nr, nc))
            return False
        BIG = 10**9
        if survives(BIG):
            return BIG
        # independent of the optimal's binary search: scan candidate waits
        # upward to the first failure. Any finite answer is bounded by the
        # grid area, so this terminates in O(m*n) iterations.
        cap = m * n + 5
        ans = -1
        d = 0
        while d <= cap:
            if survives(d):
                ans = d
                d += 1
            else:
                break
        return ans

