from collections import deque
class Solution:
    def maximumMinutes(self, grid):
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        DIRS = ((1, 0), (-1, 0), (0, 1), (0, -1))
        def multi_bfs(sources):
            dist = [[INF] * n for _ in range(m)]
            q = deque()
            for r, c in sources:
                dist[r][c] = 0
                q.append((r, c))
            while q:
                r, c = q.popleft()
                for dr, dc in DIRS:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 2 and dist[nr][nc] == INF:
                        dist[nr][nc] = dist[r][c] + 1
                        q.append((nr, nc))
            return dist
        fire = multi_bfs([(r, c) for r in range(m) for c in range(n) if grid[r][c] == 1])
        person = multi_bfs([(0, 0)])
        if person[m - 1][n - 1] == INF:
            return -1
        def can_wait(d):
            pd = [[INF] * n for _ in range(m)]
            q = deque()
            if d < fire[0][0]:
                pd[0][0] = d
                q.append((0, 0))
            while q:
                r, c = q.popleft()
                for dr, dc in DIRS:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < m and 0 <= nc < n and grid[nr][nc] != 2 and pd[nr][nc] == INF:
                        t = pd[r][c] + 1
                        if nr == m - 1 and nc == n - 1:
                            if t <= fire[nr][nc]:
                                return True
                            continue
                        if t < fire[nr][nc]:
                            pd[nr][nc] = t
                            q.append((nr, nc))
            return False
        BIG = 10**9
        if can_wait(BIG):
            return BIG
        lo, hi, ans = 0, BIG, -1
        while lo <= hi:
            mid = (lo + hi) // 2
            if can_wait(mid):
                ans = mid
                lo = mid + 1
            else:
                hi = mid - 1
        return ans

