var maximumMinutes = function(grid) {
    const m = grid.length, n = grid[0].length;
    const INF = Infinity;
    const DIRS = [[1, 0], [-1, 0], [0, 1], [0, -1]];
    function multiBfs(sources) {
        const dist = Array.from({ length: m }, () => new Array(n).fill(INF));
        let q = [];
        for (const [r, c] of sources) { dist[r][c] = 0; q.push([r, c]); }
        let head = 0;
        while (head < q.length) {
            const [r, c] = q[head++];
            for (const [dr, dc] of DIRS) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < m && nc >= 0 && nc < n && grid[nr][nc] !== 2 && dist[nr][nc] === INF) {
                    dist[nr][nc] = dist[r][c] + 1;
                    q.push([nr, nc]);
                }
            }
        }
        return dist;
    }
    const fireSources = [];
    for (let r = 0; r < m; r++) for (let c = 0; c < n; c++) if (grid[r][c] === 1) fireSources.push([r, c]);
    const fire = multiBfs(fireSources);
    const person = multiBfs([[0, 0]]);
    if (person[m - 1][n - 1] === INF) return -1;
    function canWait(d) {
        const pd = Array.from({ length: m }, () => new Array(n).fill(INF));
        let q = [];
        if (d < fire[0][0]) { pd[0][0] = d; q.push([0, 0]); }
        let head = 0;
        while (head < q.length) {
            const [r, c] = q[head++];
            for (const [dr, dc] of DIRS) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < m && nc >= 0 && nc < n && grid[nr][nc] !== 2 && pd[nr][nc] === INF) {
                    const t = pd[r][c] + 1;
                    if (nr === m - 1 && nc === n - 1) {
                        if (t <= fire[nr][nc]) return true;
                        continue;
                    }
                    if (t < fire[nr][nc]) {
                        pd[nr][nc] = t;
                        q.push([nr, nc]);
                    }
                }
            }
        }
        return false;
    }
    const BIG = 1000000000;
    if (canWait(BIG)) return BIG;
    let lo = 0, hi = BIG, ans = -1;
    while (lo <= hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (canWait(mid)) { ans = mid; lo = mid + 1; } else { hi = mid - 1; }
    }
    return ans;
};
